for (int i = 0; i < getSize(); ++i) { // Noncompliant - function call in condition
    /* getSize() called every iteration */
}

for (int i = 0; i < array.length; ++i) { // Noncompliant - property access
    if (someCondition) {
        array.length--; // Modifying the stop condition
    }
}

int limit = 10;
for (int i = 0; i < limit; ++i) { // Noncompliant - limit modified in loop
    if (i > 5) {
        limit = 15; // Changing stop condition during iteration
    }
}

compliant:
int size = getSize(); // Compliant - evaluate once before loop
for (int i = 0; i < size; ++i) {
    /* size remains constant throughout loop */
}

const int arrayLength = array.length; // Compliant - store in constant
for (int i = 0; i < arrayLength; ++i) {
    /* arrayLength cannot be modified */
}

const int limit = 10; // Compliant - constant limit
for (int i = 0; i < limit; ++i) {
    /* limit cannot be changed */
}
